export async function handleStripeWebhook(event: StripeInvoicePaidEvent) {
  const firstSeen = await markProcessedOnce(`stripe:${event.id}`);
  if (!firstSeen) return { ok: true, duplicate: true };

  const invoice: Invoice = {
    id: event.invoiceId,
    accountId: event.accountId,
    subscriptionId: event.subscriptionId,
    amountCents: event.amountPaid,
    currency: event.currency,
    region: regionFromAccount(event.accountId),
    status: "paid",
    createdAt: event.createdAt,
  };

  await recordInvoicePaid(invoice);
  return { ok: true };
}

import { readEnv } from "./env";

export type LedgerWriteMode = "legacy" | "dual" | "ledger";
export type LedgerReadMode = "legacy" | "ledger";

export function getLedgerWriteMode(): LedgerWriteMode {
  const mode = readEnv("BILLING_LEDGER_WRITE_MODE", "legacy");
  return mode === "dual" || mode === "ledger" ? mode : "legacy";
}

export function getLedgerReadMode(): LedgerReadMode {
  return readEnv("BILLING_LEDGER_READ_MODE", "legacy") === "ledger"
    ? "ledger"
    : "legacy";
}
const processed = new Set<string>();

export async function markProcessedOnce(key: string): Promise<boolean> {
  if (processed.has(key)) return false;
  processed.add(key);
  return true;
}
export type Region = "us" | "eu" | "apac";

export function regionFromAccount(accountId: string): Region {
  if (accountId.startsWith("acct_eu_")) return "eu";
  if (accountId.startsWith("acct_apac_")) return "apac";
  return "us";
}

