import { db } from "../db/client";
import type { Invoice, LedgerEvent, Refund } from "../db/types";
import { markProcessedOnce } from "../lib/idempotency";
import { assertCents } from "../lib/money";

type InvoicePaidInput = {
  invoice: Invoice;
  source: "stripe_webhook" | "billing_service";
};

type RefundCreatedInput = {
  refund: Refund;
  invoice?: Invoice;
  source: "refund_api" | "billing_service";
};

function sanitizePayload(payload: Record<string, string | number | boolean | null>) {
  return payload;
}

async function appendLedgerEvent(event: LedgerEvent): Promise<LedgerEvent | null> {
  const firstSeen = await markProcessedOnce(`ledger:${event.idempotencyKey}`);
  if (!firstSeen) return null;
  db.ledgerEvents.set(event.id, event);
  return event;
}

export async function recordInvoicePaidLedgerEvent({
  invoice,
  source,
}: InvoicePaidInput): Promise<LedgerEvent | null> {
  assertCents(invoice.amountCents);
  return appendLedgerEvent({
    id: `ledger_${invoice.region}_${invoice.id}_paid`,
    type: "invoice.paid",
    schemaVersion: 2,
    idempotencyKey: `invoice.paid:${invoice.region}:${invoice.id}`,
    region: invoice.region,
    accountId: invoice.accountId,
    invoiceId: invoice.id,
    subscriptionId: invoice.subscriptionId,
    amountCents: invoice.amountCents,
    currency: invoice.currency,
    createdAt: invoice.createdAt,
    safePayload: sanitizePayload({
      source,
      status: "paid",
    }),
  });
}

export async function recordRefundCreatedLedgerEvent({
  refund,
  invoice,
  source,
}: RefundCreatedInput): Promise<LedgerEvent | null> {
  assertCents(refund.amountCents);
  return appendLedgerEvent({
    id: `ledger_${refund.region}_${refund.id}_created`,
    type: "refund.created",
    schemaVersion: 2,
    idempotencyKey: `refund.created:${refund.region}:${refund.id}`,
    region: refund.region,
    accountId: invoice?.accountId ?? "unknown",
    invoiceId: refund.invoiceId,
    subscriptionId: invoice?.subscriptionId,
    refundId: refund.id,
    amountCents: refund.amountCents,
    currency: refund.currency,
    createdAt: refund.createdAt,
    safePayload: sanitizePayload({
      source,
      invoiceStatus: invoice?.status ?? null,
    }),
  });
}

export function listRegionalLedgerEvents(): LedgerEvent[] {
