+  const lastSeen = batch.at(-1)?.id ?? afterId ?? null;
+  return {
+    processed: batch.length,
+    cursor: lastSeen,
+    hasMore: lastSeen ? orderedInvoices.some((invoice) => invoice.id > lastSeen) : false,
